using System.IO;
using System.IO.Stream;
using OfficeOpenXml;
using OfficeOpenXml.ExcelPackage;
using OfficeOpenXml.ExcelRange;

/// <summary>
/// DemandForecast Import from Excel
/// </summary>
class KJP_SM_DemandForecastImportClass extends RunBase
{
    Dialog   dialog;
    Filename filename;
    
    private ExcelRange range;
    private List headerCellList = new List(Types::String);

    private Args importArgs;
    // Define error msg list
    private List errorMsgList = new List(Types::String);

    private container itemIdCon;
    private container itemIdConCopy;

    // Define button name
    private const str availableTypes = '.xlsx';
    private const str okButtonName = 'OkButton';
    private const str fileUploadName = 'FileUpload';
    private const str forecastSalesImportExportHeaderLayout
        = 'KJP_SM_ForecastSalesImportExportHeaderLayout';

    // Define Column for Excel
    private const str modelColumn = 'A';
    private const str dateColumn = 'B';
    private const str CustAccountIdColumn = 'C';
    private const str itemNumberColumn = 'D';
    private const str bomVersionColumn = 'E';
    private const str siteColumn = 'F';
    private const str warehouseColumn = 'G';
    private const str salesQtyColumn = 'H';
    private const str salesUnitIdColumn = 'I';
    private const str commentColumn = 'J';
    private const str propertyColumn = 'K';
    private const str activeColumn = 'L';
    private const str routeIdColumn = 'M';
    private const str recordIdColumn = 'N';
    private const str deletionFlagColumn = 'O';
    
    // Define varrable
    private const str blank = '';
    private const int num_0 = 0;
    private const int num_1 = 1;
    private const int num_2 = 2;
    private const int num_3 = 3;
    private const int num_4 = 4;
    private const int num_5 = 5;
    private const int num_6 = 6;
    private const int num_7 = 7;
    private const int num_8 = 8;
    private const int num_9 = 9;
    private const int num_10 = 10;
    private const int num_11 = 11;
    private const int num_12 = 12;
    private const int num_13 = 13;
    private const int num_14 = 14;
    private const int num_15 = 15;
    private const int num_20 = 20;
    private const int num_80 = 80;
    private const int HeaderLine = 1;
    private const str backSlash = '　/　';
    private const str squareBracketL = '[';
    private const str squareBracketR = ']';
    private const str dateNullStr ='1900/01/01';

    // Define judgment Flg
    boolean blankCheckFlg = true;
    boolean existCheckFlg = true;
    boolean modelCheckFlg = true;
    boolean dateCheckFlg = true;
    boolean itemNumberCheckFlg = true;
    boolean bomVersionCheckFlg = true;
    boolean siteCheckFlg = true;
    boolean warehouseCheckFlg = true;
    boolean salesQtyCheckFlg = true;
    boolean commentCheckFlg = true;
    boolean deletionFlagCheckFlg = true;
    boolean recIdCheckFlg = true;
    boolean resultCheckFlg = true;
    boolean custAccountIdCheckFlg = true;
    boolean salesUnitIdCheckFlg = true;
    boolean routeIdCheckFlg = true;
    boolean activeCheckFlg = true;
    boolean lifeCycleCheckFlg = true;

}

