    /// <summary>
    /// Main
    /// </summary>
    /// <param name = "_args">Args</param>
    public static void main(Args _args)
    {
        KJP_SM_DemandForecastImportClass obj = new KJP_SM_DemandForecastImportClass();

        if(obj.prompt())
        {
            obj.setArgs(_args);
            obj.runOperation();
        }
    }

/// <summary>
/// set Args from
/// </summary>
/// <param name = "_args">Args</param>
public void setArgs(Args _args)
{
    importArgs = _args;
}

    /// <summary>
    /// dialog initialization
    /// </summary>
    /// <returns>Object</returns>
    public Object dialog()
    {
        DialogGroup      dialogGroup;
        FormBuildControl formBuildControl;
        FileUploadBuild  dialogFileUpload;

        dialog = super();

        dialog.caption("@KJP:KJP102378");

        dialogGroup = dialog.addGroup();
        formBuildControl = dialog.formBuildDesign().control(dialogGroup.name());

        dialogFileUpload = formBuildControl.addControlEx(classstr(FileUpload), fileUploadName);
        dialogFileUpload.style(FileUploadStyle::MinimalWithFilename);
        dialogFileUpload.baseFileUploadStrategyClassName(classstr(FileUploadTemporaryStorageStrategy));
        dialogFileUpload.fileTypesAccepted(availableTypes);

        dialogFileUpload.browseText("@KJP:KJP101464");
        dialogFileUpload.fileNameLabel("@KJP:KJP101307");

        return dialog;
    }

/// <summary>
/// dialog Post Run process
/// </summary>
/// <param name = "_dialog">DialogRunbase</param>
public void dialogPostRun(DialogRunbase _dialog)
{
    FileUpload fileUpload = this.getFormControl(_dialog, fileUploadName);
    fileUpload.notifyUploadCompleted += eventhandler(this.uploadCompleted);
    this.setDialogOkButtonEnabled(_dialog, false);
}

    /// <summary>
    /// upload Completed process
    /// </summary>
    protected void uploadCompleted()
    {
        FileUpload fileUpload = this.getFormControl(dialog, fileUploadName);
        FileUploadTemporaryStorageResult uploadResult = fileUpload.getFileUploadResult();
         
        if (uploadResult.getUploadStatus())
        {
            fileUpload.notifyUploadCompleted -= eventhandler(this.UploadCompleted);
            filename = fileUpload.fileName();

            this.setDialogOkButtonEnabled(dialog, true);
        }
        else
        {
            warning(uploadResult.getLogMessage());
        }
    }

/// <summary>
/// set Dialog Ok Button Enabled
/// </summary>
/// <param name = "_dialog">DialogRunbase</param>
/// <param name = "_isEnabled">boolean</param>
protected void setDialogOkButtonEnabled(DialogRunbase _dialog, boolean _isEnabled)
{
    FormControl okButtonControl = this.getFormControl(_dialog, okButtonName);
    if (okButtonControl)
    {
        okButtonControl.enabled(_isEnabled);
    }
}

/// <summary>
/// get Form Control
/// </summary>
/// <param name = "_dialog">DialogRunbase</param>
/// <param name = "_controlName">str</param>
/// <returns>FormControl</returns>
protected FormControl getFormControl(DialogRunbase _dialog, str _controlName)
{
    return _dialog.formRun().control(_dialog.formRun().controlId( _controlName));
}

    /// <summary>
    /// run
    /// </summary>
    public void run()
    {
        try
        {
            ttsbegin;

            // check  data
            this.processExcFile();

            ttscommit;
        }
        catch
        {
            // When unexpected errors occur
            errorMsgList.addEnd(Exception::Error);
        }
        finally
        {
            // Go to finish process
            this.demandForecastImportFinishProcess();
        }
    
    }

    /// <summary>
    /// Choose the ForecastSales Import upload files.
    /// </summary>
    public void processExcFile()
    {
        FileUpload fileUploadControl;
        FileUploadTemporaryStorageResult fileUploadResult ;
        Stream localStream;

        fileUploadControl = this.getFormControl(dialog, fileUploadName);
        fileUploadResult = fileUploadControl.getFileUploadResult();
        localStream = fileUploadResult.openResult();

        this.readExcelData(localStream);
    }

    /// <summary>
    /// DemandForecast Import upload file check
    /// </summary>
    /// <param name = "_localStream">Stream</param>
    public void readExcelData(Stream _localStream)
    {
        int excelRowCount;
        container rangeCon;
        
        ExcelPackage   package = new ExcelPackage(_localStream);
        package.Load(_localStream);
        ExcelWorksheet worksheet = package.get_Workbook().get_Worksheets().get_Item(num_1);
        ExcelAddressBase dimension = worksheet.Dimension;
        str type_str = 'System.String';
        str type_dateTime = 'System.DateTime';
        OfficeOpenXml.ExcelRange cell;

        if(!dimension)
        {
            str errorMsg;
            errorMsg = strFmt("@KJP:KJP500199");
            errorMsgList.addEnd(errorMsg);

            // 2.2.5 Finish Process
            return;
        }
        else
        {
            range = worksheet.Cells;

            // Define header
            this.listHeaderCell();

            //2	入力ファイル
            //Input file	インポート項目チェック
            //ファイルの項目順序、項目名が定義と異なる場合、
            //エラーメッセージを表示する。#M2Before Save Process
            if (!this.checkHeaderCell())
            {
                // 2.2.5 Finish Process
                return;
            }
            else
            {
                excelRowCount = dimension.End.Row - dimension.Start.Row + num_1;
                Map fieldMapping = new Map(Types::Integer, Types::Container);
                // Start with 2 due to header excluded.
                for (int i = num_2; i <= excelRowCount; i++)
                {
                    rangeCon = conNull();

                    rangeCon += any2Str(range.get_Item(modelColumn + int2Str(i)).Value);

                    cell = range.get_Item(dateColumn + int2Str(i));

                    if(cell.Value == null)
                    {
                        rangeCon += any2Str(range.get_Item(dateColumn + int2Str(i)).Value);
                    }
                    else
                    {
                        switch(cell.Value.GetType())
                        {
                            case System.Type::GetType(type_str):
                                rangeCon += any2Str(range.get_Item(dateColumn + int2Str(i)).Value);
                                break;
                            case System.Type::GetType(type_dateTime):
                                rangeCon += datetime2Str(range.get_Item(dateColumn + int2Str(i)).Value);
                                break;
                            default:
                                rangeCon += any2Str(range.get_Item(dateColumn + int2Str(i)).Text);
                                break;
                        }
                    }

                    rangeCon += any2Str(range.get_Item(CustAccountIdColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(itemNumberColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(bomVersionColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(siteColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(warehouseColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(salesQtyColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(salesUnitIdColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(commentColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(propertyColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(activeColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(routeIdColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(recordIdColumn + int2Str(i)).Value);
                    rangeCon += any2Str(range.get_Item(deletionFlagColumn + int2Str(i)).Value);

                    // check excel content
                    if (!this.checkExcelContent(rangeCon, i))
                    {
                        resultCheckFlg = false;
                    }
                    fieldMapping.add(i, rangeCon);
                }
                if (resultCheckFlg)
                {
                    this.fromExcFileToForecastSalesForCUD(excelRowCount, fieldMapping);
                }
            }
        }
    }

/// <summary>
/// can Run In New Session
/// </summary>
/// <returns>boolean</returns>
public boolean canRunInNewSession()
{
    return false;
}

/// <summary>
/// Define header layout
/// </summary>
private void listHeaderCell()
{
    headerCellList.addEnd(modelColumn + any2Str(HeaderLine));
    headerCellList.addEnd(dateColumn + any2Str(HeaderLine));
    headerCellList.addEnd(CustAccountIdColumn + any2Str(HeaderLine));
    headerCellList.addEnd(itemNumberColumn + any2Str(HeaderLine));
    headerCellList.addEnd(bomVersionColumn + any2Str(HeaderLine));
    headerCellList.addEnd(siteColumn + any2Str(HeaderLine));
    headerCellList.addEnd(warehouseColumn + any2Str(HeaderLine));
    headerCellList.addEnd(salesQtyColumn + any2Str(HeaderLine));
    headerCellList.addEnd(salesUnitIdColumn + any2Str(HeaderLine));
    headerCellList.addEnd(commentColumn + any2Str(HeaderLine));
    headerCellList.addEnd(propertyColumn + any2Str(HeaderLine));
    headerCellList.addEnd(activeColumn + any2Str(HeaderLine));
    headerCellList.addEnd(routeIdColumn + any2Str(HeaderLine));
    headerCellList.addEnd(recordIdColumn + any2Str(HeaderLine));
    headerCellList.addEnd(deletionFlagColumn + any2Str(HeaderLine));
}

    /// <summary>
    /// Check header layout
    /// </summary>
    /// <returns>boolean</returns>
    private boolean checkHeaderCell()
    {
        str errorMsg;
        boolean chkReasult = true;

        ListEnumerator headerCellListEnumerator = headerCellList.getEnumerator();
        while (headerCellListEnumerator.moveNext())
        {
            str headerValue = KJP_CM_GeneralPurposeMaster::find(
                forecastSalesImportExportHeaderLayout,
                headerCellListEnumerator.current()).DestinationCode;
            str excelValue = range.get_Item(headerCellListEnumerator.current()).Value;

            //ファイル[A1]～[J1]の値がモデル、日付、品目番号、サイト、
            //倉庫、販売数量、コメント、プロパティ、レコードID、削除フラグ、
            //2	入力ファイル
            //Input file	インポート項目チェック
            //ファイルの項目順序、項目名が定義と異なる場合、エラーメッセージを表示する。	#M2	Before Save Process
            //#M2	KJP500223	ファイルの項目が正しくありません。
            //The file items is invalid.
            if (headerValue != excelValue)
            {
                errorMsg = strFmt("@KJP:KJP500448", headerCellListEnumerator.current(), headerValue);
                errorMsgList.addEnd(errorMsg);
                chkReasult = false;
            }
        }
        return chkReasult;
    }

    /// <summary>
    /// Check excel content
    /// </summary>
    /// <param name = "_con">container</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean checkExcelContent(container _con, int _row)
    {
        //3	入力ファイル.モデル
        //Input file.Model	モデル存在チェック
        //入力値が予測モデルに存在しない場合、エラーメッセージを表示する。	#M3	Before Save Process
        modelCheckFlg = this.validateModelExitCheck(conPeek(_con, num_1), _row);
        //4	入力ファイル.日付
        //Input file.Date	日付不正チェック
        //入力値が日付形式ではない場合、エラーメッセージを表示する。	#M0	Before Save Process
        dateCheckFlg = this.validateDateCheck(conPeek(_con, num_2), _row);
        //14	入力ファイル. 顧客 ID
        //Input file.CustAccountId	顧客存在チェック
        // 入力値が顧客に存在しない場合、エラーメッセージを表示する。	#M0	Before Save Process
        custAccountIdCheckFlg = this.validateCustAccountIdCheck(conPeek(_con, num_3), _row);
        //5	入力ファイル.品目番号
        //Input file.Item Number	品目存在チェック
        //入力値が品目に存在しない場合、エラーメッセージを表示する。	#M4	Before Save Process
        itemNumberCheckFlg = this.validateItemNumberExitCheck(conPeek(_con, num_4), _row);
        bomVersionCheckFlg = this.validateBomVersionExitCheck(conPeek(_con, num_4), conPeek(_con, num_5), _row);
        //6	入力ファイル.サイト
        //Input file.Site	サイト存在チェック
        //入力値がサイトに存在しない場合、エラーメッセージを表示する。	#M5	Before Save Process
        siteCheckFlg = this.validateSiteExitCheck(conPeek(_con, num_6), _row);
        //7	入力ファイル.倉庫
        //Input file.Warehouse	倉庫存在チェック
        //入力値が倉庫に存在しない場合、エラーメッセージを表示する。	#M6	Before Save Process
        warehouseCheckFlg = this.validateWarehouseExitCheck(conPeek(_con, num_7), _row);
        //8	入力ファイル.販売数量
        //Input file.SalesQty	数量不正チェック
        //入力値が数値形式ではない場合、エラーメッセージを表示する。	#M0	Before Save Process
        salesQtyCheckFlg = this.validateSalesQtyCheck(conPeek(_con, num_8), _row);
        //15 入力ファイル. 単位
        //Input file.SalesUnitId	単位存在チェック
        //  入力値が単位に存在しない場合、エラーメッセージを表示する。	#M0	Before Save Process
        salesUnitIdCheckFlg = this.validateSalesUnitIdCheck(conPeek(_con, num_4), conPeek(_con, num_9), _row);
        //Comment Lengh不正チェック
        commentCheckFlg = this.validateCommentCheck(conPeek(_con, num_10), _row);
        //16	入力ファイル. 工順番号
        //Input file.RouteId	工順番号存在チェック
        //入力値が工順番号に存在しない場合、エラーメッセージを表示する。	#M0	Before Save Process
        routeIdCheckFlg = this.validateRouteIdCheck(conPeek(_con, num_4), conPeek(_con, num_2),
            conPeek(_con, num_8), conPeek(_con, num_13), _row);
        //9	入力ファイル.削除フラグ
        //Input file.Deletion Flag	フラグ不正チェック
        //入力値が未入力,0,1ではない場合、エラーメッセージを表示する。	#M0	Before Save Process
        deletionFlagCheckFlg = this.validateDeletionFlagCheck(conPeek(_con, num_15), _row);
        //11	入力ファイル.RECID
        //Input file.RECID	既存レコード存在チェック
        //入力ファイルのRECIDが入力ありの場合で、該当レコードが存在しない場合、エラーメッセージを表示する。	#M8	Before Save Process
        //Input file.RECID	複数行チェック
        //入力ファイルのRECIDが入力ありの場合で、同じRECIDが複数行ある場合、エラーメッセージを表示する。
        //Input file.Deletion Flag	新規登録＆削除フラグチェック
        //入力ファイルのRECIDが入力なしの場合で、削除フラグが1の場合、エラーメッセージを表示する。
        recIdCheckFlg = this.validateRecIDExitCheck(conPeek(_con, num_14), conPeek(_con, num_15), _row);
        //17	入力ファイル.有効
        //Input file.Active	有効不正チェック
        //入力値が未入力,0,1ではない場合、エラーメッセージを表示する。	#M0	Before Save Process
        activeCheckFlg = this.validateActiveCheck(conPeek(_con, num_12), _row);

        //Block Rule Check
        lifeCycleCheckFlg = this.validateLifeCycleStatusCheck(conPeek(_con, num_4),
            conPeek(_con, num_2), conPeek(_con, num_6), conPeek(_con, num_7), _row);

        if (modelCheckFlg && dateCheckFlg && itemNumberCheckFlg && bomVersionCheckFlg && siteCheckFlg
            && warehouseCheckFlg && salesQtyCheckFlg && commentCheckFlg && deletionFlagCheckFlg && recIdCheckFlg
            && custAccountIdCheckFlg && salesUnitIdCheckFlg && routeIdCheckFlg && activeCheckFlg && lifeCycleCheckFlg)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    /// <summary>
    /// validate Life Cycle Status Check
    /// </summary>
    /// <param name = "_itemNumber">_itemNumber</param>
    /// <param name = "_date">_date</param>
    /// <param name = "_siteId">_siteId</param>
    /// <param name = "_WarehouseId">_WarehouseId</param>
    /// <param name = "_row">_row</param>
    /// <returns>true/false</returns>
    private boolean validateLifeCycleStatusCheck(str _itemNumber, str _date, str _siteId, str _WarehouseId, int _row)
    {
        existCheckFlg = true;
        str errorHeaderMsg = strFmt("@KJP:KJP500220",_row , "@KJP:KJP101383") ;
        str errorExistMsg;
        str errorAllMsg = blank;
        TransDate startDate = str2Date(_date, 321);
        InventDim   inventDim;
        InventDimId inventDimId;
        KJP_SM_CheckLifeCycleStatusRuleBlock checkLifeCycleStatusRuleBlock = new KJP_SM_CheckLifeCycleStatusRuleBlock();

        inventDim.InventSiteId = _siteId;
        inventDim.InventLocationId = _WarehouseId;
        inventDimId = InventDim::findOrCreate(inventDim).inventDimId;

        if (checkLifeCycleStatusRuleBlock.isBlocked(_itemNumber, inventDimId, startDate))
        {
            errorExistMsg = checkLifeCycleStatusRuleBlock.parmErrorMsg();
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorExistMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorExistMsg + squareBracketR;
            }
            existCheckFlg = false;
        }
        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }
        if (existCheckFlg)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    /// <summary>
    /// Check excel content of _model
    /// </summary>
    /// <param name = "_model">_model</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateModelExitCheck (str _model, int _row)
    {
        existCheckFlg = true;
        str errorHeaderMsg = strFmt("@KJP:KJP500220", _row, "@KJP:KJP102377") ;
        str errorExistMsg = strFmt("@KJP:KJP500224", _model);
        str errorAllMsg = blank;

        // Exist check in ForecastModel Table.
        if(!ForecastModel::exist(HeadingSub::Heading, _model, _model))
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorExistMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorExistMsg + squareBracketR;
            }
            existCheckFlg = false;
        }
        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }
        if (existCheckFlg)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    /// <summary>
    /// Check excel content of Date
    /// </summary>
    /// <param name = "_date">Date</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateDateCheck(str _date, int _row)
    {
        blankCheckFlg = true;
        dateCheckFlg = true;
        str errorHeaderMsg = strFmt("@KJP:KJP500220", _row, "@KJP:KJP101405") ;
        str errorMandatoryMsg = strFmt("@KJP:KJP500164", "@KJP:KJP101405");
        str errorFormatMsg = strFmt("@KJP:KJP500172", _date);
        str errorAllMsg = blank;

        date strDate = str2Date(_date, 321);

        // Date blank check
        if (blank == _date || _date == dateNullStr)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorMandatoryMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorMandatoryMsg + squareBracketR;
            }
            blankCheckFlg = false;
        }
        else
        {
            // Date Format check
            if (!strDate)
            {
                if (blank == errorAllMsg)
                {
                    errorAllMsg = errorHeaderMsg + squareBracketL + errorFormatMsg + squareBracketR;
                }
                else
                {
                    errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorFormatMsg + squareBracketR;
                }
                dateCheckFlg = false;
            }
        }
        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }
        if (blankCheckFlg && dateCheckFlg)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    /// <summary>
    /// Check excel content of itemNumber
    /// </summary>
    /// <param name = "_itemNumber">itemNumber</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateItemNumberExitCheck(str _itemNumber, int _row)
    {
        existCheckFlg = true;
        str errorHeaderMsg = strFmt("@KJP:KJP500220",_row , "@KJP:KJP101383") ;
        str errorExistMsg = strFmt("@KJP:KJP500225", _itemNumber);
        str errorAllMsg = blank;

        // Exist check in InventTable Table.
        if (!InventTable::exist(_itemNumber))
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorExistMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorExistMsg + squareBracketR;
            }
            existCheckFlg = false;
        }
        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }
        if (existCheckFlg)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

    /// <summary>
    /// Check excel content of _bomVersion
    /// </summary>
    /// <param name = "_itemNumber">itemNumber</param>
