    /// <summary>
    /// Check excel content of salesQty
    /// </summary>
    /// <param name = "_salesQty">salesQty</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateSalesQtyCheck(str _salesQty, int _row)
    {
        blankCheckFlg = true;
        salesQtyCheckFlg = true;
        str errorHeaderMsg = strFmt("@KJP:KJP500220",_row , "@KJP:KJP101406") ;
        str errorMandatoryMsg = strFmt("@KJP:KJP500164", "@KJP:KJP101406");
        str errorValueMsg = strFmt("@KJP:KJP500172", _salesQty);
        str errorAllMsg = blank;

        real quantityStringToReal;
        str  quantityRealToString;

        quantityStringToReal = any2Real(_salesQty);
        quantityRealToString = any2Str(quantityStringToReal);

        // Mandatory check
        if(blank == _salesQty)
        {
            if (blank == errorAllMsg)
            {
                errorAllMsg = errorHeaderMsg + squareBracketL + errorMandatoryMsg + squareBracketR;
            }
            else
            {
                errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorMandatoryMsg + squareBracketR;
            }
            blankCheckFlg = false;
        }
        else
        {
            // Number check and Value check
            if(quantityStringToReal <= num_0 || _salesQty != quantityRealToString)
            {
                if (blank == errorAllMsg)
                {
                    errorAllMsg = errorHeaderMsg + squareBracketL + errorValueMsg + squareBracketR;
                }
                else
                {
                    errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorValueMsg + squareBracketR;
                }
                salesQtyCheckFlg = false;
            }
        }
        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }
        if (blankCheckFlg && salesQtyCheckFlg)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

