    /// <summary>
    /// Check excel content of RecID
    /// </summary>
    /// <param name = "_recID">RecID</param>
    /// <param name = "_deletionFlag">deletionFlag</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateRecIDExitCheck(str _recID, str _deletionFlag, int _row)
    {
        existCheckFlg = true;
        str errorHeaderMsg = strFmt("@KJP:KJP500220",_row , "@KJP:KJP100749") ;
        str errorExistMsg = strFmt("@KJP:KJP500226", _recID);
        str errorDoubleExistMsg = strFmt("@KJP:KJP500453", _recID);
        str errorRecIDAnddeletionFlagMsg = strFmt("@KJP:KJP500459");
        str errorAllMsg = blank;

        if (_recID != blank)
        {
            //既存レコード存在チェック
            if ( !ForecastSales::findRecId(any2Int64(_recID)))
            {
                if (blank == errorAllMsg)
                {
                    errorAllMsg = errorHeaderMsg + squareBracketL + errorExistMsg + squareBracketR;
                }
                else
                {
                    errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorExistMsg + squareBracketR;
                }
                existCheckFlg = false;
            }
            //複数行チェック
            if (!nullValue(itemIdCon) && conLen(itemIdCon) > 0)
            {
                for (int i = 1; i <= conLen(itemIdCon); i++)
                {
                    if (_recID == conPeek(itemIdCon, i))
                    {
                        if (blank == errorAllMsg)
                        {
                            errorAllMsg = errorHeaderMsg + squareBracketL + errorDoubleExistMsg + squareBracketR;
                        }
                        else
                        {
                            errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorDoubleExistMsg + squareBracketR;
                        }
                        existCheckFlg = false;
                    }
                    else
                    {
                        if (conFind(itemIdConCopy, _recID) == 0)
                        {
                            itemIdConCopy += _recID;
                        }
                    }
                }
                itemIdCon = itemIdConCopy;
            }
            else
            {
                if (conFind(itemIdCon, _recID) == 0)
                {
                    itemIdCon += _recID;
                    itemIdConCopy += _recID;
                }
            }
        }
        else
        {
            //新規登録＆削除フラグチェック
            if (_deletionFlag == int2Str(enum2int(NoYes::Yes)))
            {
                if (blank == errorAllMsg)
                {
                    errorAllMsg = errorHeaderMsg + squareBracketL + errorRecIDAnddeletionFlagMsg + squareBracketR;
                }
                else
                {
                    errorAllMsg = errorAllMsg + backSlash + squareBracketL + errorRecIDAnddeletionFlagMsg + squareBracketR;
                }
                existCheckFlg = false;
            }
        }

        if (blank != errorAllMsg)
        {
            errorMsgList.addEnd(errorAllMsg);
        }
        if (existCheckFlg)
        {
            return true;
        }
        else
        {
            return false;
        }
    }

