    /// <summary>
    /// Check excel content of _salesUnitId
    /// </summary>
    /// <param name = "_itemId">_itemId</param>
    /// <param name = "_excelUnitId">_excelUnitId</param>
    /// <param name = "_row">int</param>
    /// <returns>boolean</returns>
    private boolean validateSalesUnitIdCheck (str _itemId, str _excelUnitId, int _row)
    {
        existCheckFlg = true;
        str errorHeaderMsg = strFmt("@KJP:KJP500220", _row, "@KJP:KJP101389") ;
        str errorExistMsg = strFmt("@SYP4986038", "@KJP:KJP101389", _excelUnitId, "@KJP:KJP100706");
        str errorConvertMsg;
        str errorAllMsg = blank;
        UnitOfMeasureFromRecId fromRecId;
        UnitOfMeasureFromRecId toRecId;
        boolean canConvert;
        boolean ret = true;

        if (_excelUnitId == blank)
        {
            return true;
        }

        // UnitID exists check
        if (!UnitOfMeasure::findBySymbol(_excelUnitId).RecId)
        {
            errorAllMsg = errorHeaderMsg + squareBracketL + errorExistMsg + squareBracketR;
            errorMsgList.addEnd(errorAllMsg);

            return false;
        }

        // get InventUnitId
        UnitOfMeasureSymbol inventUnitId = InventTableModule::find(_itemId, ModuleInventPurchSales::Invent).UnitId;

        // only InventUnitId exist
        if (inventUnitId != blank)
        {
            if (_excelUnitId == inventUnitId)
            {
                ret = true;
            }
            else
            {
                fromRecId = UnitOfMeasure::findBySymbol(_excelUnitId).RecId;
                toRecId = UnitOfMeasure::findBySymbol(inventUnitId).RecId;
                canConvert = UnitOfMeasureConverter::canBeConverted(fromRecId, toRecId, inventTable::itemProduct(_itemId));
                if (!canConvert)
                {
                    errorConvertMsg = strFmt("@SYS310324", _excelUnitId, inventUnitId, _itemId);
                    errorAllMsg = errorHeaderMsg + squareBracketL + errorConvertMsg + squareBracketR;
                    errorMsgList.addEnd(errorAllMsg);
                    ret = false;
                }
            }
        }

        return ret;
    }

