    /// <summary>
    /// Excel Data to forecastSsles
    /// </summary>
    /// <param name = "_excelRowCount">excelRowCount</param>
    /// <param name = "_fieldMapping">fieldMapping</param>
    private void fromExcFileToForecastSalesForCUD(Integer _excelRowCount, Map _fieldMapping)
    {
        container rangeCon;

        ForecastSales forecastSales;
        InventDim newInventDim;

        // Start with 2 due to header excluded.
        for (int i = num_2; i <= _excelRowCount; i++)
        {
            rangeCon = conNull();
            forecastSales.clear();
            newInventDim.clear();
            rangeCon = _fieldMapping.lookup(i);
            if (blank == conPeek(rangeCon, num_14))
            {
                //モデル
                forecastSales.ModelId = conPeek(rangeCon, num_1);
                forecastSales.Cov = ForecastModel::find(HeadingSub::Heading, forecastSales.ModelId).Cov;
                //日付
                forecastSales.StartDate = str2Date(conPeek(rangeCon, num_2), 321);
                //顧客 ID
                forecastSales.CustAccountId = conPeek(rangeCon, num_3);
                //顧客グループ
                forecastSales.CustGroupId = CustTable::find(conPeek(rangeCon, num_3)).CustGroup;
                forecastSales.TaxGroupId = CustTable::find(conPeek(rangeCon, num_3)).TaxGroup;
                //品目番号
                forecastSales.ItemId = conPeek(rangeCon, num_4);
                InventTable inventTable = InventTable::find(forecastSales.ItemId);
                //BOM
                forecastSales.ItemBOMId = conPeek(rangeCon, num_5);
                //サイト
                newInventDim.InventSiteId = conPeek(rangeCon, num_6);
                //倉庫
                newInventDim.InventLocationId = conPeek(rangeCon, num_7);
                forecastSales.InventDimId = InventDim::findOrCreate(newInventDim).inventDimId;
                forecastSales.CostPrice = inventTable.costPcsPrice(forecastSales.InventDimId,
                    InventDim::find(forecastSales.InventDimId), null, forecastSales.StartDate);
                //販売数量
                forecastSales.SalesQty = conPeek(rangeCon, num_8);
                               
                //販売単位
                forecastSales.SalesUnitId = conPeek(rangeCon, num_9);

                //在庫数量
                forecastSales.InventQty = this.getInventQty(forecastSales.ItemId, forecastSales.SalesQty, forecastSales.SalesUnitId);

                //コメント
                forecastSales.Comment = conPeek(rangeCon, num_10);

                forecastSales.TaxItemGroupId =
                    InventTableModule::find(forecastSales.ItemId, ModuleInventPurchSales::Sales).TaxItemGroupId;
                forecastSales.ProjCategoryId = inventTable.ProjCategoryId;
                forecastSales.DefaultDimension = inventTable.DefaultDimension;

                //品目番号紐付く項目
                forecastSales.salesPurchLineInterface().setPriceAgreement(newInventDim,true);
                forecastSales.updateAmount();
                if (forecastSales.ProjId)
                {
                    forecastSales.ProjLinePropertyId = ProjLinePropertySetup::findLinePropertyId(forecastSales.ProjId,forecastSales.ProjCategoryId);
                }
                forecastSales.PdsCWUnitId = PdsCatchWeightItem::pdsCWUnitId(forecastSales.ItemId);
                //販売通貨
                forecastSales.Currency = Ledger::accountingCurrency(CompanyInfo::current());
                //品目グループ
                forecastSales.ItemGroupId = inventTable.itemGroupId();
                //有効
                if (conPeek(rangeCon, num_12) == blank)
                {
                    forecastSales.Active = NoYes::Yes;
                }
                else
                {
                    forecastSales.Active = conPeek(rangeCon, num_12);
                }

                forecastSales.ItemRouteId = conPeek(rangeCon, num_13);

                //登録
                forecastSales.insert();
            }
            else
            {
                //「削除フラグ」に1が入った状態でインポートすると、
                //「RECID」をキー項目としてD365内の既存レコードを削除する
                if (conPeek(rangeCon, num_15) == int2Str(enum2int(NoYes::Yes)))
                {
                    select forupdate forecastSales
                        where forecastSales.RecId == any2Int64(conPeek(rangeCon, num_14));

                    if (forecastSales.RecId)
                    {
                        forecastSales.delete();
                    }
                }
                else
                {
                    while select forUpdate forecastSales
                        where forecastSales.RecId == any2Int64(conPeek(rangeCon, num_14))
                    {
                        //モデル
                        forecastSales.ModelId = conPeek(rangeCon, num_1);
                        forecastSales.Cov = ForecastModel::find(HeadingSub::Heading, forecastSales.ModelId).Cov;
                        //日付
                        forecastSales.StartDate = str2Date(conPeek(rangeCon, num_2), 321);
                        //顧客 ID
                        forecastSales.CustAccountId = conPeek(rangeCon, num_3);
                        //顧客グループ
                        forecastSales.CustGroupId = CustTable::find(conPeek(rangeCon, num_3)).CustGroup;
                        forecastSales.TaxGroupId = CustTable::find(conPeek(rangeCon, num_3)).TaxGroup;
                        //品目番号
                        forecastSales.ItemId = conPeek(rangeCon, num_4);
                        InventTable inventTable = InventTable::find(forecastSales.ItemId);
                        //BOM
                        forecastSales.ItemBOMId = conPeek(rangeCon, num_5);
                        //サイト
                        newInventDim.InventSiteId = conPeek(rangeCon, num_6);
                        //倉庫
                        newInventDim.InventLocationId = conPeek(rangeCon, num_7);
                        forecastSales.InventDimId = InventDim::findOrCreate(newInventDim).inventDimId;
                        forecastSales.CostPrice = inventTable.costPcsPrice(forecastSales.InventDimId,
                            InventDim::find(forecastSales.InventDimId), null, forecastSales.StartDate);
                        //販売数量
                        forecastSales.SalesQty = conPeek(rangeCon, num_8);

                        //販売単位
                        forecastSales.SalesUnitId = conPeek(rangeCon, num_9);

                        //在庫数量
                        forecastSales.InventQty = this.getInventQty(forecastSales.ItemId, forecastSales.SalesQty, forecastSales.SalesUnitId);

                        //コメント
                        forecastSales.Comment= conPeek(rangeCon, num_10);

                        forecastSales.TaxItemGroupId =
                            InventTableModule::find(forecastSales.ItemId, ModuleInventPurchSales::Sales).TaxItemGroupId;
                        forecastSales.ProjCategoryId = inventTable.ProjCategoryId;
                        forecastSales.DefaultDimension = inventTable.DefaultDimension;

                        //品目番号紐付く項目
                        forecastSales.salesPurchLineInterface().setPriceAgreement(newInventDim,true);
                        forecastSales.updateAmount();
                        if (forecastSales.ProjId)
                        {
                            forecastSales.ProjLinePropertyId = ProjLinePropertySetup::findLinePropertyId(forecastSales.ProjId,forecastSales.ProjCategoryId);
                        }
                        forecastSales.PdsCWUnitId = PdsCatchWeightItem::pdsCWUnitId(forecastSales.ItemId);
                        //品目グループ
                        forecastSales.ItemGroupId = inventTable.itemGroupId();
                        //有効
                        if (conPeek(rangeCon, num_12) == blank)
                        {
                            forecastSales.Active = NoYes::Yes;
                        }
                        else
                        {
                            forecastSales.Active = conPeek(rangeCon, num_12);
                        }

                        forecastSales.ItemRouteId = conPeek(rangeCon, num_13);

                        //更新
                        forecastSales.update();
                    }
                    
                }
            }
        }
    }

    /// <summary>
    /// get InventQty
    /// </summary>
    /// <param name = "_itemId">_itemId</param>
    /// <param name = "_salesQty">_salesQty</param>
    /// <param name = "_unitId">_unitId</param>
    /// <returns>InventQty</returns>
    private InventQty getInventQty(ItemId _itemId, SalesQty _salesQty, UnitOfMeasureSymbol _unitId)
    {
        InventQty inventQty;

        // get InventUnitId
        UnitOfMeasureSymbol inventUnitId = InventTableModule::find(_itemId, ModuleInventPurchSales::Invent).UnitId;

        if (_unitId && inventUnitId)
        {
            inventQty =
                UnitOfMeasureConverter::convert(_salesQty,
                UnitOfMeasure::unitOfMeasureIdBySymbol(_unitId),
                UnitOfMeasure::unitOfMeasureIdBySymbol(inventUnitId),
                NoYes::Yes, inventTable::itemProduct(_itemId));
        }
        else
        {
            inventQty = _salesQty;
        }

        return inventQty;
    }

    /// <summary>
    /// Finish Process
    /// </summary>
    private void demandForecastImportFinishProcess()
    {
        if (dialog.closedOk())
        {
            Args args = new Args();

            args.caller(importArgs);
            args.parmObject(errorMsgList);
            args.parmEnum(NoYes::No);
            
            new MenuFunction(menuItemDisplayStr(KJP_SM_DemandForecastImportResult), MenuItemType::Display).run(args);
        }
    }
